// Parse Evolution API MESSAGES_UPSERT payload
const body = $input.first().json.body || $input.first().json;
const data = body.data || {};
const key = data.key || {};

const remoteJid = key.remoteJid || '';
const phone = remoteJid.split('@')[0] || null;
const fromMe = Boolean(key.fromMe);
const msgId = key.id || null;
const pushName = data.pushName || null;

// Skip group messages
if (remoteJid.endsWith('@g.us')) return [];

const m = data.message || {};
let text = null;
const mt = data.messageType || 'unknown';

if (m.conversation) text = m.conversation;
else if (m.extendedTextMessage && m.extendedTextMessage.text) text = m.extendedTextMessage.text;
else if (m.imageMessage && m.imageMessage.caption) text = m.imageMessage.caption;
else if (m.videoMessage && m.videoMessage.caption) text = m.videoMessage.caption;
else if (m.documentMessage && m.documentMessage.caption) text = m.documentMessage.caption;
else if (m.audioMessage) text = '[audio]';
else if (m.stickerMessage) text = '[sticker]';
else if (m.locationMessage) text = '[location]';
else if (m.contactMessage) text = '[contact]';

if (!msgId || !phone) return [];

return [{
  json: {
    evolution_msg_id: msgId,
    phone,
    contact_name: fromMe ? null : pushName,
    direction: fromMe ? 'out' : 'in',
    body: text,
    message_type: mt,
    conversation_id: remoteJid,
    metadata: JSON.stringify({
      instance: body.instance || null,
      event: body.event || null,
      timestamp: data.messageTimestamp || null
    })
  }
}];
